/**
 * TestResults.tsx — Morning Report Viewer
 *
 * Displays the dashboard-data-YYYY-MM-DD.json generated by the morning-report-generator.
 * Layout:
 *   1. Header + date selector
 *   2. Summary cards (Duration, Cycles, Pass/Fail, Bugs, Fixed, Needs Human)
 *   3. Events table — sortable, filterable by type/impact/area
 */
import { useState, useMemo } from 'react'
import {
  Clock, RefreshCw, Bug, CheckCircle, XCircle, AlertTriangle,
  Zap, ChevronUp, ChevronDown, ChevronsUpDown,
} from 'lucide-react'
import { Loading, EmptyState } from '../components/common/Loading'
import { useTestReportDates, useTestReport, type TestResultEvent } from '../api/hooks'

// ─── Helpers ────────────────────────────────────────────────────────────────

const IMPACT_ORDER: Record<string, number> = { P0: 0, P1: 1, P2: 2, P3: 3 }

function impactColor(impact?: string): string {
  switch (impact) {
    case 'P0': return 'var(--accent-red)'
    case 'P1': return 'var(--accent-amber)'
    case 'P2': return 'var(--accent-blue)'
    default:   return 'var(--text-tertiary)'
  }
}

function typeColor(type?: string): string {
  switch (type) {
    case 'bug_discovered':   return 'var(--accent-red)'
    case 'bug_fixed':        return 'var(--accent-green)'
    case 'feature_verified': return 'var(--accent-green)'
    case 'fix_failed':       return 'var(--accent-amber)'
    case 'needs_human':      return 'var(--accent-purple)'
    case 'perf_regression':  return 'var(--accent-amber)'
    case 'perf_improved':    return 'var(--accent-green)'
    case 'ui_issue':         return 'var(--accent-blue)'
    case 'flow_broken':      return 'var(--accent-red)'
    default:                 return 'var(--text-secondary)'
  }
}

function typeLabel(type?: string): string {
  switch (type) {
    case 'bug_discovered':   return 'Bug'
    case 'bug_fixed':        return 'Fixed'
    case 'feature_verified': return 'Verified'
    case 'fix_failed':       return 'Fix Failed'
    case 'needs_human':      return 'Needs Human'
    case 'perf_regression':  return 'Perf ↓'
    case 'perf_improved':    return 'Perf ↑'
    case 'ui_issue':         return 'UI'
    case 'flow_broken':      return 'Flow Broken'
    default:                 return type || '—'
  }
}

function fmtTs(ts?: string): string {
  if (!ts) return '—'
  try {
    const d = new Date(ts)
    return d.toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit', second: '2-digit', hour12: false })
  } catch {
    return ts
  }
}

// ─── Summary Card ────────────────────────────────────────────────────────────

interface SummaryCardProps {
  label: string
  value: string | number
  accentColor: string
  icon: React.ReactNode
}

function SummaryCard({ label, value, accentColor, icon }: SummaryCardProps) {
  return (
    <div
      className="rounded-xl p-[18px] flex flex-col gap-3 relative overflow-hidden"
      style={{
        background: 'var(--bg-surface)',
        border: '1px solid var(--border-subtle)',
        boxShadow: '0 1px 3px rgba(0,0,0,0.12)',
      }}
    >
      {/* Top accent bar */}
      <div
        className="absolute top-0 left-0 right-0 h-[2px]"
        style={{ background: accentColor, opacity: 0.7 }}
      />
      <div className="flex items-center justify-between mt-1">
        <span
          className="text-[10px] font-bold uppercase tracking-[0.05em]"
          style={{ color: 'var(--text-tertiary)' }}
        >
          {label}
        </span>
        <span style={{ color: accentColor, opacity: 0.8 }}>{icon}</span>
      </div>
      <span
        className="font-mono text-[26px] font-extrabold leading-none"
        style={{ color: accentColor, fontFamily: 'var(--font-mono)' }}
      >
        {value}
      </span>
    </div>
  )
}

// ─── Sort Control ─────────────────────────────────────────────────────────────

type SortKey = 'ts' | 'type' | 'impact' | 'area'
type SortDir = 'asc' | 'desc'

function SortIcon({ col, sortKey, sortDir }: { col: SortKey; sortKey: SortKey; sortDir: SortDir }) {
  if (col !== sortKey) return <ChevronsUpDown className="w-3 h-3 opacity-30" />
  return sortDir === 'asc'
    ? <ChevronUp className="w-3 h-3" />
    : <ChevronDown className="w-3 h-3" />
}

// ─── Events Table ─────────────────────────────────────────────────────────────

interface EventsTableProps {
  events: TestResultEvent[]
}

const TYPE_FILTERS = [
  { value: '', label: 'All Types' },
  { value: 'bug_discovered', label: 'Bugs' },
  { value: 'bug_fixed', label: 'Fixed' },
  { value: 'feature_verified', label: 'Verified' },
  { value: 'fix_failed', label: 'Fix Failed' },
  { value: 'needs_human', label: 'Needs Human' },
  { value: 'perf_regression', label: 'Perf ↓' },
  { value: 'perf_improved', label: 'Perf ↑' },
  { value: 'ui_issue', label: 'UI' },
  { value: 'flow_broken', label: 'Flow Broken' },
]

const IMPACT_FILTERS = [
  { value: '', label: 'All Impact' },
  { value: 'P0', label: 'P0' },
  { value: 'P1', label: 'P1' },
  { value: 'P2', label: 'P2' },
  { value: 'P3', label: 'P3' },
]

function EventsTable({ events }: EventsTableProps) {
  const [typeFilter, setTypeFilter] = useState('')
  const [impactFilter, setImpactFilter] = useState('')
  const [sortKey, setSortKey] = useState<SortKey>('ts')
  const [sortDir, setSortDir] = useState<SortDir>('asc')

  const handleSort = (col: SortKey) => {
    if (col === sortKey) {
      setSortDir(d => d === 'asc' ? 'desc' : 'asc')
    } else {
      setSortKey(col)
      setSortDir('asc')
    }
  }

  const filtered = useMemo(() => {
    let rows = [...events]
    if (typeFilter) rows = rows.filter(e => e.type === typeFilter)
    if (impactFilter) rows = rows.filter(e => e.impact === impactFilter)
    rows.sort((a, b) => {
      let va = '', vb = ''
      if (sortKey === 'ts') {
        va = a.ts || ''; vb = b.ts || ''
      } else if (sortKey === 'impact') {
        va = String(IMPACT_ORDER[a.impact || ''] ?? 99)
        vb = String(IMPACT_ORDER[b.impact || ''] ?? 99)
      } else {
        va = String(a[sortKey] || ''); vb = String(b[sortKey] || '')
      }
      const cmp = va.localeCompare(vb)
      return sortDir === 'asc' ? cmp : -cmp
    })
    return rows
  }, [events, typeFilter, impactFilter, sortKey, sortDir])

  const selectStyle: React.CSSProperties = {
    background: 'var(--bg-elevated)',
    border: '1px solid var(--border-default)',
    borderRadius: '6px',
    color: 'var(--text-secondary)',
    fontSize: '11px',
    padding: '4px 8px',
    outline: 'none',
    cursor: 'pointer',
  }

  const thStyle: React.CSSProperties = {
    fontSize: '10px',
    fontWeight: 700,
    textTransform: 'uppercase' as const,
    letterSpacing: '0.05em',
    color: 'var(--text-tertiary)',
    padding: '8px 12px',
    textAlign: 'left' as const,
    borderBottom: '1px solid var(--border-subtle)',
    cursor: 'pointer',
    userSelect: 'none',
    whiteSpace: 'nowrap',
  }

  return (
    <div
      className="rounded-xl overflow-hidden"
      style={{ border: '1px solid var(--border-subtle)', background: 'var(--bg-surface)' }}
    >
      {/* Filters */}
      <div className="flex items-center gap-3 px-4 py-3 border-b" style={{ borderColor: 'var(--border-subtle)' }}>
        <span className="text-[11px] font-semibold" style={{ color: 'var(--text-secondary)' }}>
          {filtered.length} / {events.length} events
        </span>
        <select style={selectStyle} value={typeFilter} onChange={e => setTypeFilter(e.target.value)}>
          {TYPE_FILTERS.map(f => <option key={f.value} value={f.value}>{f.label}</option>)}
        </select>
        <select style={selectStyle} value={impactFilter} onChange={e => setImpactFilter(e.target.value)}>
          {IMPACT_FILTERS.map(f => <option key={f.value} value={f.value}>{f.label}</option>)}
        </select>
      </div>

      {filtered.length === 0 ? (
        <div className="py-10 text-center text-[13px]" style={{ color: 'var(--text-tertiary)' }}>
          No events match the current filters
        </div>
      ) : (
        <div className="overflow-x-auto">
          <table className="w-full border-collapse" style={{ tableLayout: 'fixed' }}>
            <colgroup>
              <col style={{ width: '70px' }} />
              <col style={{ width: '110px' }} />
              <col style={{ width: '60px' }} />
              <col style={{ width: '130px' }} />
              <col />
            </colgroup>
            <thead>
              <tr style={{ background: 'var(--bg-elevated)' }}>
                {([ ['ts', 'Time'], ['type', 'Type'], ['impact', 'Impact'], ['area', 'Area'] ] as [SortKey, string][]).map(([col, label]) => (
                  <th key={col} style={thStyle} onClick={() => handleSort(col)}>
                    <span className="flex items-center gap-1">
                      {label}
                      <SortIcon col={col} sortKey={sortKey} sortDir={sortDir} />
                    </span>
                  </th>
                ))}
                <th style={{ ...thStyle, cursor: 'default' }}>Detail</th>
              </tr>
            </thead>
            <tbody>
              {filtered.map((ev, idx) => {
                const impact = ev.impact || ''
                const borderColor = impactColor(impact)
                const isEven = idx % 2 === 0
                return (
                  <tr
                    key={idx}
                    style={{ background: isEven ? 'transparent' : 'var(--bg-elevated)' }}
                    onMouseEnter={e => { (e.currentTarget as HTMLElement).style.background = 'var(--bg-hover)' }}
                    onMouseLeave={e => { (e.currentTarget as HTMLElement).style.background = isEven ? 'transparent' : 'var(--bg-elevated)' }}
                  >
                    {/* Time */}
                    <td
                      className="pl-0"
                      style={{
                        padding: '7px 12px 7px 0',
                        borderLeft: `3px solid ${borderColor}`,
                        paddingLeft: '10px',
                        fontSize: '11px',
                        fontFamily: 'var(--font-mono)',
                        color: 'var(--text-tertiary)',
                        whiteSpace: 'nowrap',
                      }}
                    >
                      {fmtTs(ev.ts)}
                    </td>
                    {/* Type badge */}
                    <td style={{ padding: '7px 12px' }}>
                      <span
                        className="inline-block rounded"
                        style={{
                          fontSize: '10px',
                          fontWeight: 700,
                          fontFamily: 'var(--font-mono)',
                          padding: '2px 6px',
                          background: `color-mix(in srgb, ${typeColor(ev.type)} 12%, transparent)`,
                          color: typeColor(ev.type),
                        }}
                      >
                        {typeLabel(ev.type)}
                      </span>
                    </td>
                    {/* Impact */}
                    <td style={{ padding: '7px 12px' }}>
                      {impact ? (
                        <span
                          className="inline-block rounded"
                          style={{
                            fontSize: '10px',
                            fontWeight: 700,
                            fontFamily: 'var(--font-mono)',
                            padding: '2px 5px',
                            background: `color-mix(in srgb, ${borderColor} 12%, transparent)`,
                            color: borderColor,
                          }}
                        >
                          {impact}
                        </span>
                      ) : <span style={{ color: 'var(--text-tertiary)', fontSize: '12px' }}>—</span>}
                    </td>
                    {/* Area */}
                    <td
                      style={{
                        padding: '7px 12px',
                        fontSize: '12px',
                        fontWeight: 600,
                        color: 'var(--text-secondary)',
                        whiteSpace: 'nowrap',
                        overflow: 'hidden',
                        textOverflow: 'ellipsis',
                      }}
                      title={ev.area}
                    >
                      {ev.area || '—'}
                    </td>
                    {/* Detail */}
                    <td
                      style={{
                        padding: '7px 12px',
                        fontSize: '12px',
                        color: 'var(--text-primary)',
                        overflow: 'hidden',
                        textOverflow: 'ellipsis',
                        whiteSpace: 'nowrap',
                        maxWidth: 0,
                      }}
                      title={ev.detail}
                    >
                      {ev.detail || '—'}
                      {ev.result && (
                        <span
                          className="ml-2 inline-block rounded"
                          style={{
                            fontSize: '10px',
                            fontFamily: 'var(--font-mono)',
                            fontWeight: 700,
                            padding: '1px 5px',
                            background: ev.result === 'pass' ? 'var(--accent-green-dim)' : 'var(--accent-red-dim)',
                            color: ev.result === 'pass' ? 'var(--accent-green)' : 'var(--accent-red)',
                          }}
                        >
                          {ev.result}
                        </span>
                      )}
                      {ev.method && (
                        <span
                          className="ml-2 inline-block rounded"
                          style={{
                            fontSize: '10px',
                            fontFamily: 'var(--font-mono)',
                            fontWeight: 700,
                            padding: '1px 5px',
                            background: 'var(--accent-purple-dim)',
                            color: 'var(--accent-purple)',
                          }}
                        >
                          {ev.method}
                        </span>
                      )}
                    </td>
                  </tr>
                )
              })}
            </tbody>
          </table>
        </div>
      )}
    </div>
  )
}

// ─── Main Page ────────────────────────────────────────────────────────────────

export default function TestResults() {
  const { data: datesData, isLoading: datesLoading } = useTestReportDates()
  const dates = datesData?.dates ?? []

  const [selectedDate, setSelectedDate] = useState<string | undefined>(undefined)
  // Use first date as default once loaded
  const effectiveDate = selectedDate ?? (dates.length > 0 ? dates[0] : undefined)

  const { data, isLoading, isError } = useTestReport(effectiveDate)

  if (datesLoading || (isLoading && !data)) {
    return <Loading />
  }

  if (!effectiveDate || isError || !data) {
    return (
      <div style={{ animation: 'fadeInUp 0.35s ease' }}>
        {/* Header */}
        <div className="mb-6">
          <h1
            className="text-[20px] font-extrabold"
            style={{ color: 'var(--text-primary)', letterSpacing: '-0.03em' }}
          >
            Test Results
          </h1>
          <p className="text-[12px] mt-0.5 font-mono" style={{ color: 'var(--text-tertiary)' }}>
            Morning report from overnight test runs
          </p>
        </div>
        <EmptyState
          icon="📊"
          title="No Reports Yet"
          description="Run the morning report generator to create a dashboard-data-YYYY-MM-DD.json file."
        />
      </div>
    )
  }

  const { summary, events, duration, cycles, runDate } = data

  const summaryCards = [
    {
      label: 'Duration',
      value: duration,
      accentColor: 'var(--accent-blue)',
      icon: <Clock className="w-4 h-4" />,
    },
    {
      label: 'Cycles',
      value: cycles,
      accentColor: 'var(--accent-purple)',
      icon: <RefreshCw className="w-4 h-4" />,
    },
    {
      label: 'Verified Pass',
      value: summary.verified_pass,
      accentColor: 'var(--accent-green)',
      icon: <CheckCircle className="w-4 h-4" />,
    },
    {
      label: 'Verified Fail',
      value: summary.verified_fail,
      accentColor: summary.verified_fail > 0 ? 'var(--accent-red)' : 'var(--text-tertiary)',
      icon: <XCircle className="w-4 h-4" />,
    },
    {
      label: 'Bugs Found',
      value: summary.bugs,
      accentColor: summary.bugs > 0 ? 'var(--accent-amber)' : 'var(--text-tertiary)',
      icon: <Bug className="w-4 h-4" />,
    },
    {
      label: 'Auto-Fixed',
      value: summary.fixed,
      accentColor: summary.fixed > 0 ? 'var(--accent-green)' : 'var(--text-tertiary)',
      icon: <Zap className="w-4 h-4" />,
    },
    {
      label: 'Fix Failed',
      value: summary.fix_failed,
      accentColor: summary.fix_failed > 0 ? 'var(--accent-red)' : 'var(--text-tertiary)',
      icon: <XCircle className="w-4 h-4" />,
    },
    {
      label: 'Needs Human',
      value: summary.needs_human,
      accentColor: summary.needs_human > 0 ? 'var(--accent-purple)' : 'var(--text-tertiary)',
      icon: <AlertTriangle className="w-4 h-4" />,
    },
  ]

  const selectStyle: React.CSSProperties = {
    background: 'var(--bg-elevated)',
    border: '1px solid var(--border-default)',
    borderRadius: '6px',
    color: 'var(--text-secondary)',
    fontSize: '12px',
    padding: '5px 10px',
    outline: 'none',
    cursor: 'pointer',
    fontFamily: 'var(--font-mono)',
  }

  return (
    <div style={{ animation: 'fadeInUp 0.35s ease' }}>
      {/* Header */}
      <div className="flex items-start justify-between mb-6">
        <div>
          <h1
            className="text-[20px] font-extrabold"
            style={{ color: 'var(--text-primary)', letterSpacing: '-0.03em' }}
          >
            Test Results
          </h1>
          <p className="text-[12px] mt-0.5 font-mono" style={{ color: 'var(--text-tertiary)' }}>
            Morning report — {runDate}
          </p>
        </div>
        {dates.length > 1 && (
          <div className="flex items-center gap-2">
            <span className="text-[11px]" style={{ color: 'var(--text-tertiary)' }}>Report date:</span>
            <select
              style={selectStyle}
              value={effectiveDate}
              onChange={e => setSelectedDate(e.target.value)}
            >
              {dates.map(d => (
                <option key={d} value={d}>{d}</option>
              ))}
            </select>
          </div>
        )}
      </div>

      {/* Summary cards */}
      <div
        className="grid gap-3 mb-6"
        style={{ gridTemplateColumns: 'repeat(auto-fill, minmax(150px, 1fr))' }}
      >
        {summaryCards.map(card => (
          <SummaryCard key={card.label} {...card} />
        ))}
      </div>

      {/* Events table */}
      <div className="mb-2">
        <h2
          className="text-[13px] font-bold mb-3"
          style={{ color: 'var(--text-primary)' }}
        >
          All Events
          <span
            className="ml-2 text-[11px] font-mono font-normal"
            style={{ color: 'var(--text-tertiary)' }}
          >
            {events.length} total
          </span>
        </h2>
        {events.length === 0 ? (
          <div
            className="rounded-xl py-10 text-center text-[13px]"
            style={{ background: 'var(--bg-surface)', border: '1px solid var(--border-subtle)', color: 'var(--text-tertiary)' }}
          >
            No events recorded in this report
          </div>
        ) : (
          <EventsTable events={events} />
        )}
      </div>
    </div>
  )
}
